previewCss:
.darma-loader-uiverse-soft-progress-breath {
  width: fit-content;
  height: fit-content;
  display: flex;
  align-items: center;
  justify-content: center;
  position: relative;
}

.darma-loader-uiverse-soft-progress-breath__progress-loader {
  position: relative;
  width: 150px;
  background: rgba(236, 236, 238, 0.253);
  height: 10px;
  border-radius: 7px;
  overflow: hidden;
}

.darma-loader-uiverse-soft-progress-breath__progress {
width: 1px;
height: 10px;
border-radius: 7px;
background: rgb(255, 255, 255);
transition: 0.5s;
animation: darma-loader-uiverse-soft-progress-breath-loading_44 5s cubic-bezier(0.4, 1.01, 1, 1) infinite;
}

@keyframes darma-loader-uiverse-soft-progress-breath-loading_44 {
0% {
width: 0%;
}

50% {
width: 100%;
}

100% {
width: 0%;
}
}

